// Parse ICRTouch Z-Report from email body. Returns null fields if can't parse.
// Format reference (from benchmark fixtures):
//   ICRTouch Z-Report
//   Date 08/05/2026 Session: Dinner
//   Gross £2,809.44
//   Net  £2,341.20
//   VAT  £468.24
//   Covers: 87

const body = ($json.body_text || '').replace(/\r/g, '');

function money(text, label) {
  const re = new RegExp(label + '\\s*[:\\s]?\\s*\u00a3?\\s*([\\d,]+(?:\\.\\d{1,2})?)', 'i');
  const m = body.match(re);
  if (!m) return null;
  return parseFloat(m[1].replace(/,/g, ''));
}

function num(text, label) {
  const re = new RegExp(label + '\\s*[:\\s]?\\s*(\\d+)', 'i');
  const m = body.match(re);
  return m ? parseInt(m[1], 10) : null;
}

// Date — handle DD/MM/YYYY → YYYY-MM-DD
let reportDate = null;
const dm = body.match(/Date\s+(\d{1,2})[\/\-](\d{1,2})[\/\-](\d{4})/i);
if (dm) reportDate = `${dm[3]}-${dm[2].padStart(2,'0')}-${dm[1].padStart(2,'0')}`;

// Session — Lunch / Dinner / Breakfast / etc.
let session = null;
const sm = body.match(/Session[:\s]+(\w+)/i) || body.match(/(Lunch|Dinner|Breakfast|Late|Brunch)\b/i);
if (sm) session = sm[1];

const gross  = money(body, 'Gross');
const net    = money(body, 'Net');
const vat    = money(body, 'VAT');
const covers = num(body, 'Covers');

const parseable = !!(reportDate && session && (gross !== null));

return { json: {
  email_id:    $json.email_id,
  report_date: reportDate,
  session:     session,
  gross:       gross,
  net:         net,
  vat:         vat,
  covers:      covers,
  raw_text:    body.substring(0, 2000),
  parseable:   parseable,
  from_address: $json.from_address,
  subject:     $json.subject,
} };
